var CSbody=document.querySelector("body");const CSnavbarMenu=document.querySelector("#cs-navigation"),CShamburgerMenu=document.querySelector("#cs-navigation .cs-toggle");function ariaExpanded(){const e=document.querySelector("#cs-expanded");"false"===e.getAttribute("aria-expanded")?e.setAttribute("aria-expanded","true"):e.setAttribute("aria-expanded","false")}CShamburgerMenu.addEventListener("click",function(){CShamburgerMenu.classList.toggle("cs-active"),CSnavbarMenu.classList.toggle("cs-active"),CSbody.classList.toggle("cs-open"),ariaExpanded()});const dropDowns=Array.from(document.querySelectorAll("#cs-navigation .cs-dropdown"));for(const e of dropDowns){const t=()=>{e.classList.toggle("cs-active")};e.addEventListener("click",t)}const image=document.querySelector("#perspective-image");image.addEventListener("mousemove",e=>{const{width:t,height:o,left:a,top:s}=image.getBoundingClientRect(),n=e.clientX-a,c=t/2,r=o/2,i=10*((e.clientY-s-r)/r),d=10*-((n-c)/c);image.style.transform=`rotateX(${i}deg) rotateY(${d}deg)`}),image.addEventListener("mouseleave",()=>{image.style.transform="rotateX(0deg) rotateY(0deg)"});const dotArea={x:8,y:8,width:40,height:40};image.addEventListener("click",e=>{const t=e.offsetX,o=e.offsetY;if(console.log(`MouseX: ${t}, MouseY: ${o}`),t>=dotArea.x&&t<=dotArea.x+dotArea.width&&o>=dotArea.y&&o<=dotArea.y+dotArea.height){console.log("User clicked the sensitive area");const e=document.getElementById("content-image");image.style.display="none",e.style.display="block"}});const faqItems=Array.from(document.querySelectorAll(".cs-faq-item"));for(const e of faqItems){const t=()=>{const t=e.classList.contains("active");faqItems.forEach(e=>e.classList.remove("active")),t||e.classList.add("active")};e.addEventListener("click",t)}